mapper.select:
select m3.*,m5.ThirdPartyName,m6.NAME tranName from (select m1.task_id, (case when m2.work_untis_name is null then '-' else m2.work_untis_name end) taskName, sum(case m1.success when 1 then 1 else 0 end) success, sum(case m1.success when 0 then 1 else 0 end) failed from VzDataQuality.dbo.tb_collectionlog m1 left join VzDataQuality.dbo.tb_collectiontimingdata m2 on m1.task_id=m2.id where 1=1
and m1.begin_time >= #{beginTime}
and m1.begin_time <= #{endTime}
and m2.work_untis_name like CONCAT('%',#{taskName},'%')
and m2.type=#{type}
group by m1.task_id,m2.work_untis_name
) m3 left join VzDataQuality.dbo.tb_collectiontimingdata m4 on m3.task_id=m4.id left join VzDataQuality.dbo.ThridParty m5 on m4.company_id=m5.SysId left join VzDataQuality.dbo.r_transformation m6 on m4.tran_id=m6.ID_TRANSFORMATION
